const img = (id: string) => `https://images.unsplash.com/photo-${id}?w=800&q=80`;
const imgs3 = (i: number) => JSON.stringify([img(P[i % 15]), img(P[(i + 5) % 15]), img(P[(i + 10) % 15])]);

// ── Hours templates ───────────────────────────────────────────────────────────
const H = (o: string, c: string, sc: string, so: string, scl: string) => JSON.stringify([
  { day: "Monday",    time: `${o} – ${c}` },
  { day: "Tuesday",   time: `${o} – ${c}` },
  { day: "Wednesday", time: `${o} – ${c}` },
  { day: "Thursday",  time: `${o} – ${c}` },
  { day: "Friday",    time: `${o} – ${c}` },
  { day: "Saturday",  time: `${o} – ${sc}` },
  { day: "Sunday",    time: `${so} – ${scl}` },
]);
const H1 = H("9:00 AM", "7:00 PM", "6:00 PM", "10:00 AM", "5:00 PM");
const H2 = H("8:00 AM", "8:00 PM", "7:00 PM", "9:00 AM",  "6:00 PM");
const H3 = H("10:00 AM","6:00 PM", "5:00 PM", "11:00 AM", "4:00 PM");

// ── Compact shop tuple ────────────────────────────────────────────────────────
// [slug, name, tagline, uniqueDetail, neighborhood, addr, zip, phone, rating, reviews, cats[], tags[], price, est, delivery, featured, imgIdx]
type Tup = [string,string,string,string,string,string,string,string,number,number,string[],string[],string,string,boolean,boolean,number];

type City = { name: string; slug: string; state: string; shops: Tup[] };

const DESC = (name: string, nbhd: string, city: string, state: string, tagline: string, unique: string, cats: string[]) =>
  `${name} is ${city}'s beloved floral destination in the ${nbhd} neighborhood, proudly serving ${state} customers with exceptional craftsmanship and care. ${unique} Specializing in ${cats.slice(0,2).join(" and ").toLowerCase()}, our team designs everything from intimate hand-tied bouquets to full-scale wedding and event installations. We offer same-day delivery across ${city}, custom arrangements tailored to your vision, and a rotating selection of fresh seasonal blooms sourced daily from trusted growers. ${tagline}`;

const makeShop = (citySlug: string, city: string, state: string, areaCode: string, emailDomain: string) => (t: Tup) => {
  const [slug, name, tagline, unique, nbhd, addr, zip, phone, rating, reviews, cats, tags, price, est, del, ft, imgIdx] = t;
  return {
    slug,
    name,
    tagline,
    description: DESC(name, nbhd, city, state, tagline, unique, cats),
    address: addr,
    city, state, citySlug,
    pincode: zip,
    phone,
    email: `hello@${emailDomain}`,
    website: `https://${emailDomain}`,
    rating,
    reviewCount: reviews,
    images: imgs3(imgIdx),
    categories: JSON.stringify(cats),
    tags: JSON.stringify(tags),
    hours: imgIdx % 3 === 0 ? H1 : imgIdx % 3 === 1 ? H2 : H3,
    open: true,
    verified: true,
    featured: ft,
    established: est,
    priceRange: price,
    deliveryAvailable: del,
    status: "approved",
  };
};

