// ═══════════════════════════════════════════════════════════════════════════════
// SEED
// ═══════════════════════════════════════════════════════════════════════════════

async function main() {
  const areaCodes: Record<string, string> = {};
  let total = 0;

  for (const city of CITIES) {
    const emailDomain = city.slug.replace(/-/g, "") + "flowers.com";
    const builder = makeShop(city.slug, city.name, city.state, areaCodes[city.slug] ?? "", emailDomain);

    for (const shop of city.shops) {
      const data = builder(shop);
      await prisma.listing.upsert({
        where: { slug: data.slug },
        create: data,
        update: data,
      });
      total++;
    }
    console.log(`  ✓ ${city.name}, ${city.state} (${city.shops.length} shops)`);
  }

  console.log(`\n✅ Seeded ${total} listings across ${CITIES.length} cities`);
}

main().catch(console.error).finally(() => prisma.$disconnect());
